    private int _totalCount = 0;
    private const int PageSize = 50;

    protected override async Task OnInitializedAsync() => await LoadAsync();

    private async Task ApplyFilterAsync()
    {
        _page = 0;
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        var outcome = _filterOutcome == "Win" ? TradeOutcome.Win
                    : _filterOutcome == "Loss" ? TradeOutcome.Loss
                    : (TradeOutcome?)null;

        var filter = new AdminTradeFilter
        {
            Engine = string.IsNullOrEmpty(_filterEngine) ? null : _filterEngine,
            Symbol = string.IsNullOrEmpty(_filterSymbol) ? null : _filterSymbol,
            Outcome = outcome,
            Page = _page,
            PageSize = PageSize
        };

