        _totalCount = await DataService.GetTradeCountAsync(filter);
        _totalPages = Math.Max(1, (int)Math.Ceiling(_totalCount / (double)PageSize));
    }

    private async Task PrevPageAsync() { if (_page > 0) { _page--; await LoadAsync(); } }
    private async Task NextPageAsync() { if (_page < _totalPages - 1) { _page++; await LoadAsync(); } }
}
