@code {
    // Individual bound fields (records are immutable, can't bind directly)
    private decimal _minEdge;
    private decimal _kellyFraction;
    private decimal _maxPositionSize;
    private decimal _bankroll;
    private decimal _minConfidence;
    private int _maxOpenPositions;
    private bool _paperPolyEnabled;
    private bool _paperBinanceEnabled;
    private bool _saved;

    protected override void OnInitialized() => LoadFromConfig(ConfigSvc.GetConfig());

    private void LoadFromConfig(TradingConfig c)
    {
        _minEdge = c.MinEdge;
        _kellyFraction = c.KellyFraction;
        _maxPositionSize = c.MaxPositionSize;
        _bankroll = c.Bankroll;
        _minConfidence = c.MinConfidence;
        _maxOpenPositions = c.MaxOpenPositions;
        _paperPolyEnabled = c.PaperPolyEnabled;
        _paperBinanceEnabled = c.PaperBinanceEnabled;
    }

    private void SaveConfig()
    {
        ConfigSvc.Apply(new TradingConfig
        {
            MinEdge = _minEdge,
            KellyFraction = _kellyFraction,
            MaxPositionSize = _maxPositionSize,
            Bankroll = _bankroll,
            MinConfidence = _minConfidence,
            MaxOpenPositions = _maxOpenPositions,
            PaperPolyEnabled = _paperPolyEnabled,
            PaperBinanceEnabled = _paperBinanceEnabled
        });
        _saved = true;
        _ = Task.Delay(3000).ContinueWith(_ => InvokeAsync(() => { _saved = false; StateHasChanged(); }));
    }

    private void ResetConfig() { LoadFromConfig(new TradingConfig()); _saved = false; }
}
