        {
            <div class="px-4 py-1.5 font-mono text-xs flex gap-3"
                 style="border-bottom: 1px solid var(--color-border-subtle);">
                <span style="color: var(--color-text-muted); flex-shrink: 0;">@log.Timestamp.ToString("HH:mm:ss")</span>
                <span class="flex-shrink-0 font-bold w-8" style="color: @LevelColor(log.Level);">@log.Level</span>
                <span style="color: var(--color-text-secondary); word-break: break-all;">@log.Message</span>
            </div>
        }
        @if (FilteredLogs.Count == 0)
