@code {
    private List<AdminLogEntry> _logs = [];
    private string _levelFilter = "ALL";

    private List<AdminLogEntry> FilteredLogs => _levelFilter == "ALL"
        ? _logs
        : _logs.Where(l => l.Level.StartsWith(_levelFilter, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync() => await RefreshAsync();

    private async Task RefreshAsync()
    {
        _logs = await DataService.GetRecentLogsAsync(200);
        _logs.Reverse(); // En yeni en uste
    }

    private static string LevelColor(string level) => level.ToUpperInvariant() switch
    {
        "ERR" or "FTL" => "var(--color-accent-red)",
        "WRN" => "var(--color-accent-gold)",
        "INF" => "var(--color-accent-blue)",
        _ => "var(--color-text-muted)"
    };
}
